    raise RuntimeError(f"VRAM pre-check failed: {vram_check.get('message')}")
env_cfg = create_isaaclab_env(task_name=TASK_NAME, robot_path=ROBOT_PATH, task_type="manipulation", num_envs=NUM_ENVS, env_spacing={{primary_robot.env_spacing}})
launch_result = launch_training(task=TASK_NAME, algo={{training_run.algo}}, num_steps=NUM_STEPS, num_envs=NUM_ENVS, checkpoint_dir=RUN_DIR)
run_id = launch_result.get("run_id", TASK_NAME) if isinstance(launch_result, dict) else TASK_NAME
steps_completed = 0
latest_reward = 0.0
for _ in range(30):
    status = get_training_status(run_id=run_id, log_dir=RUN_DIR)
    if isinstance(status, dict):
        steps_completed = status.get("step") or status.get("steps_completed", 0) or 0
        latest_reward = status.get("latest_reward", 0.0) or 0.0
        if steps_completed >= MIN_STEPS_FOR_SUCCESS or status.get("state") in ("finished", "crashed"):
            break
    pass  # removed sandbox-illegal call
pause_training(run_id=run_id)
cabinet_joint_positions = None
drawer_joint_readable = False
try:
    cabinet_joint_positions = get_joint_positions(articulation=CABINET_PATH)
    drawer_joint_readable = cabinet_joint_positions is not None and (
        (isinstance(cabinet_joint_positions, dict) and bool(cabinet_joint_positions.get("positions"))) or
        (isinstance(cabinet_joint_positions, list) and len(cabinet_joint_positions) > 0)
    )
except Exception as exc:
    print(f"[WARN] get_joint_positions: {exc!r}")
effort_report = None
effort_saturating = False
try:
    effort_report = monitor_joint_effort(articulation_path=ROBOT_PATH, duration_seconds=2.0)
    if isinstance(effort_report, dict):
        sat = effort_report.get("saturated_joints", []) or effort_report.get("saturating", [])
        effort_saturating = isinstance(sat, list) and len(sat) > 0
except Exception as exc:
    print(f"[WARN] monitor_joint_effort: {exc!r}")
STOCK_REWARD_CODE = "# IsaacLab stock cabinet reward for {} \ndef stock_cabinet_reward(env, robot, cabinet):\n    return env.cfg.rewards".format(TASK_NAME)
eval_result = evaluate_reward(reward_code=STOCK_REWARD_CODE, env_id=TASK_NAME, num_steps=200)
fitness = eval_result.get("fitness", 0.0) if isinstance(eval_result, dict) else 0.0
checkpoint = checkpoint_training(run_id=run_id, include_replay_buffer=False, tag={{training_run.checkpoint_tag}})
checkpoint_path = checkpoint.get("checkpoint_path", RUN_DIR + "/cabinet_baseline_v1.pt") if isinstance(checkpoint, dict) else RUN_DIR + "/cabinet_baseline_v1.pt"
steps_ok = steps_completed >= MIN_STEPS_FOR_SUCCESS
checkpoint_ok = bool(checkpoint_path)
fitness_ok = fitness != 0
joint_ok = drawer_joint_readable
